//! Compiler-emitted rules for the World Sim engine.
//!
//! Milestone 2 integration (2026-04-19): this crate is the canonical owner of
//! the Event taxonomy and the niche-ID newtypes. The old dep direction
//! (`engine_rules → engine`) was reversed — `engine` now depends on
//! `engine_rules` and re-exports from it so existing call sites keep working.
//!
//! Everything under `events/` and the body of `schema.rs` is generated by
//! `dsl_compiler` from `assets/sim/*.sim`. Regenerate with:
//!
//! ```bash
//! cargo run --bin xtask -- compile-dsl
//! ```
//!
//! The `ids` and `id_serde` modules are hand-written (for now); they mirror
//! the old `engine::ids` byte-for-byte. When the compiler grows entity
//! emission in a later milestone, the IDs move into generated output too.

pub mod config;
pub mod entities;
pub mod events;
pub mod id_serde;
pub mod ids;
pub mod schema;
pub mod scoring;
pub mod types;

pub use events::Event;
pub use schema::EVENT_HASH;
